    ecosystem:{title:"The Complete Ecosystem",subtitle:"AI Revenue Systems + Marketing Authority",description:ecoDesc,
      ioFeatures:ioF,comFeatures:comF,
      comLinks:CL},
    testimonials:tms,faqs,
    cta:{title:ctaTitle,subtitle:ctaSub,buttonText:ctaBtn},
    relatedLandingPages:related||[],relatedServices:RS,comLinks:CL
