pages.forEach(p => {
  if (p.pipeline && p.pipeline.steps) {
    p.pipeline.steps.forEach(s => {
      if (s.description === undefined && s.desc !== undefined) {
        s.description = s.desc; delete s.desc;
      }
    });
  }
});

